<?php
namespace Nistruct\ContentAI\Setup\Patch\Data;
use Magento\Framework\Setup\ModuleDataSetupInterface; use Magento\Framework\Setup\Patch\DataPatchInterface;
class BackfillReportProductSku implements DataPatchInterface { private $moduleDataSetup; public function __construct(ModuleDataSetupInterface $moduleDataSetup){$this->moduleDataSetup=$moduleDataSetup;} public function apply(){ $c=$this->moduleDataSetup->getConnection();$this->moduleDataSetup->getConnection()->startSetup();$report=$this->moduleDataSetup->getTable('nistruct_contentai_report');$product=$this->moduleDataSetup->getTable('catalog_product_entity');if($c->isTableExists($report)&&$c->tableColumnExists($report,'product_sku')){$c->query(sprintf('UPDATE %s r LEFT JOIN %s p ON p.entity_id = r.product_id SET r.product_sku = p.sku WHERE r.product_sku IS NULL AND r.product_id IS NOT NULL',$c->quoteIdentifier($report),$c->quoteIdentifier($product)));}$this->moduleDataSetup->getConnection()->endSetup();} public static function getDependencies(){return [];} public function getAliases(){return [];} }
